#SBATCH --job-name=iqtree_oxphos
#SBATCH --array=1-96
#SBATCH --cpus-per-task=4
#SBATCH --mem=8G
#SBATCH --time=4:00:00
#SBATCH --output=/work/WorkDevelopmentC/ad2347/OxPhos_DAV/logs/iqtree_%A_%a.out
#SBATCH --error=/work/WorkDevelopmentC/ad2347/OxPhos_DAV/logs/iqtree_%A_%a.err
#SBATCH --export=ALL
